   661 |   case CmpInst::ICMP_UGE:
   662 |   case CmpInst::ICMP_SGT:
   663 |   case CmpInst::ICMP_SGE: {
   664 |     Pred = CmpInst::getSwappedPredicate(Pred);
   665 |     std::swap(Op0, Op1);
   666 |     break;
   667 |   }
   668 |   case CmpInst::ICMP_EQ:
   669 |     if (match(Op1, m_Zero())) {
   670 |       Pred = CmpInst::ICMP_ULE;
   671 |     } else {
   672 |       IsEq = true;
   673 |       Pred = CmpInst::ICMP_ULE;
   674 |     }
   675 |     break;
   676 |   case CmpInst::ICMP_NE:
   677 |     if (match(Op1, m_Zero())) {
